/**
 * Formats a date to relative time (e.g., "2 days ago")
 * @param {string} dateString - ISO date string
 * @returns {string} Formatted relative date
 */
export const formatRelativeDate = (dateString) => {
  if (!dateString) return '';

  const date = new Date(dateString);
  const now = new Date();
  const diffMs = now - date;
  const diffSecs = Math.floor(diffMs / 1000);
  const diffMins = Math.floor(diffSecs / 60);
  const diffHours = Math.floor(diffMins / 60);
  const diffDays = Math.floor(diffHours / 24);

  if (diffSecs < 60) return __('Just now', 'uixpress');
  if (diffMins < 60)
    return `${diffMins} ${
      diffMins === 1 ? __('minute', 'uixpress') : __('minutes', 'uixpress')
    } ${__('ago', 'uixpress')}`;
  if (diffHours < 24)
    return `${diffHours} ${
      diffHours === 1 ? __('hour', 'uixpress') : __('hours', 'uixpress')
    } ${__('ago', 'uixpress')}`;
  if (diffDays < 7)
    return `${diffDays} ${
      diffDays === 1 ? __('day', 'uixpress') : __('days', 'uixpress')
    } ${__('ago', 'uixpress')}`;

  // Format as date if older than a week
  return date.toLocaleDateString();
};
