/**
 * Gets post status label with translation
 * @param {string} status - Post status
 * @returns {string} Translated status label
 */
export const getStatusLabelText = (status) => {
  const labels = {
    publish: __('Published', 'uixpress'),
    draft: __('Draft', 'uixpress'),
    pending: __('Pending', 'uixpress'),
    private: __('Private', 'uixpress'),
    future: __('Scheduled', 'uixpress'),
  };
  return labels[status] || status;
};

