<script setup>
import { computed, ref } from 'vue';
import Modal from '@/components/utility/modal/index.vue';
import LayoutFixDialog from '../layout-fix-dialog.vue';
import SearchInput from './SearchInput.vue';
import SearchOnboarding from './SearchOnboarding.vue';
import EmptyStateNoResults from './EmptyStateNoResults.vue';
import EmptyStateInitial from './EmptyStateInitial.vue';
import CommandHelp from './CommandHelp.vue';
import SearchHistory from './SearchHistory.vue';
import RecentlyAccessed from './RecentlyAccessed.vue';
import FrequentlyUsed from './FrequentlyUsed.vue';
import QuickActions from './QuickActions.vue';
import SearchResults from './SearchResults.vue';
import KeyboardShortcuts from './KeyboardShortcuts.vue';

const props = defineProps({
  searchQuery: {
    type: String,
    default: '',
  },
  isLoading: {
    type: Boolean,
    default: false,
  },
  activeResultIndex: {
    type: Number,
    default: 0,
  },
  showHistoryDropdown: {
    type: Boolean,
    default: false,
  },
  parsedQuery: {
    type: Object,
    required: true,
  },
  commandFilter: {
    type: String,
    default: '',
  },
  filteredSearchResults: {
    type: Object,
    required: true,
  },
  hasSeenOnboarding: {
    type: Boolean,
    default: false,
  },
  showOnboarding: {
    type: Boolean,
    default: false,
  },
  hasNoResults: {
    type: Boolean,
    default: false,
  },
  searchHistory: {
    type: Array,
    default: () => [],
  },
  filteredQuickActions: {
    type: Array,
    default: () => [],
  },
  flattenedResultsLength: {
    type: Number,
    default: 0,
  },
  showLayoutFixDialog: {
    type: Boolean,
    default: false,
  },
  markOnboardingSeen: {
    type: Function,
    required: true,
  },
  handleExampleSearch: {
    type: Function,
    required: true,
  },
  showOnboardingTutorial: {
    type: Function,
    required: true,
  },
  clearHistory: {
    type: Function,
    required: true,
  },
  getFilteredRecentlyAccessed: {
    type: Function,
    required: true,
  },
  getFilteredFrequentlyUsed: {
    type: Function,
    required: true,
  },
  getItemIndex: {
    type: Function,
    required: true,
  },
  handleItemClick: {
    type: Function,
    required: true,
  },
  getActionIndex: {
    type: Function,
    required: true,
  },
  handleActionClick: {
    type: Function,
    required: true,
  },
  getResultIndex: {
    type: Function,
    required: true,
  },
  getItemLink: {
    type: Function,
    required: true,
  },
  getCategoryName: {
    type: Function,
    required: true,
  },
});

const emit = defineEmits([
  'update:searchQuery',
  'keyup-down',
  'keyup-up',
  'keyup-enter',
  'input-focus',
  'input-blur',
  'close-layout-fix',
]);

const searchModalRef = ref(null);

const localSearchQuery = computed({
  get: () => props.searchQuery,
  set: (value) => emit('update:searchQuery', value),
});

const show = (evt) => {
  searchModalRef.value?.show(evt);
};

const close = () => {
  searchModalRef.value?.close();
};

const isOpen = computed(() => searchModalRef.value?.isOpen?.value ?? false);

defineExpose({
  show,
  close,
  isOpen,
});
</script>

<template>
  <Modal ref="searchModalRef" position="top">
    <div
      id="uixpress-search-modal"
      class="mx-auto p-6 w-[500px] flex flex-col gap-6 max-w-[100vw]"
    >
      <SearchInput
        v-model="localSearchQuery"
        :is-loading="isLoading"
        @keyup-down="emit('keyup-down', $event)"
        @keyup-up="emit('keyup-up', $event)"
        @keyup-enter="emit('keyup-enter', $event)"
        @focus="emit('input-focus', $event)"
        @blur="emit('input-blur', $event)"
      />

      <div class="relative">
        <div class="flex flex-col gap-6 max-h-[70dvh] overflow-auto">
          <SearchOnboarding
            :visible="showOnboarding && !hasSeenOnboarding"
            @dismiss="markOnboardingSeen"
            @example-click="handleExampleSearch"
          />

          <EmptyStateNoResults
            v-if="
              hasNoResults &&
              !showOnboarding &&
              parsedQuery.cleanQuery &&
              parsedQuery.cleanQuery.length > 0
            "
            @view-commands="localSearchQuery = '?help'"
            @clear-search="localSearchQuery = ''"
          />

          <EmptyStateInitial
            v-if="
              hasNoResults &&
              !showOnboarding &&
              !parsedQuery.cleanQuery &&
              !isLoading
            "
            :has-seen-onboarding="hasSeenOnboarding"
            @example-click="handleExampleSearch"
            @show-tutorial="showOnboardingTutorial"
          />

          <CommandHelp v-if="commandFilter === 'help'" />

          <SearchHistory
            v-if="showHistoryDropdown && !parsedQuery.cleanQuery"
            :history="searchHistory"
            @select="localSearchQuery = $event"
            @clear="clearHistory"
          />

          <RecentlyAccessed
            v-if="!parsedQuery.cleanQuery"
            :items="getFilteredRecentlyAccessed()"
            :active-index="activeResultIndex"
            :get-item-index="getItemIndex"
            @item-click="(item) => handleItemClick(item, item.category)"
          />

          <FrequentlyUsed
            v-if="!parsedQuery.cleanQuery"
            :items="getFilteredFrequentlyUsed()"
            :active-index="activeResultIndex"
            :get-item-index="getItemIndex"
            @item-click="(item) => handleItemClick(item, item.category)"
          />

          <QuickActions
            :actions="filteredQuickActions"
            :active-index="activeResultIndex"
            :get-action-index="getActionIndex"
            @action-click="handleActionClick"
          />

          <SearchResults
            :results="filteredSearchResults"
            :active-index="activeResultIndex"
            :get-result-index="getResultIndex"
            :get-item-link="getItemLink"
            :get-category-name="getCategoryName"
            @item-click="handleItemClick"
          />
        </div>

        <div
          class="absolute bottom-0 left-0 right-0 h-10 bg-gradient-to-t from-white dark:from-zinc-900 to-transparent pointer-events-none"
          v-if="!isLoading && flattenedResultsLength > 20"
        />
      </div>

      <KeyboardShortcuts />
    </div>
  </Modal>

  <LayoutFixDialog
    :visible="showLayoutFixDialog"
    @close="emit('close-layout-fix')"
  />
</template>

<style scoped>
:global(body.uixpress-frontend-minimal-active #uixpress-search-modal) {
  font-size: 14px !important;
  line-height: 20px !important;
}

:global(body.uixpress-frontend-minimal-active #uixpress-search-modal input),
:global(body.uixpress-frontend-minimal-active #uixpress-search-modal button),
:global(body.uixpress-frontend-minimal-active #uixpress-search-modal a),
:global(body.uixpress-frontend-minimal-active #uixpress-search-modal li),
:global(body.uixpress-frontend-minimal-active #uixpress-search-modal p),
:global(body.uixpress-frontend-minimal-active #uixpress-search-modal span),
:global(body.uixpress-frontend-minimal-active #uixpress-search-modal div) {
  font-size: inherit !important;
}

:global(
    body.uixpress-frontend-minimal-active #uixpress-search-modal [class*='text-xs']
  ) {
  font-size: 12px !important;
